    -- Write response channel
    S_AXI_BRESP   : out std_logic_vector(1 downto 0);
    S_AXI_BVALID  : out std_logic;
    S_AXI_BREADY  : in  std_logic;
    -- Read address channel
    S_AXI_ARADDR  : in  std_logic_vector(C_S_AXI_ADDR_WIDTH-1 downto 0);
    S_AXI_ARPROT  : in  std_logic_vector(2 downto 0);
    S_AXI_ARVALID : in  std_logic;
    S_AXI_ARREADY : out std_logic;
    -- Read data channel
    S_AXI_RDATA   : out std_logic_vector(C_S_AXI_DATA_WIDTH-1 downto 0);
    S_AXI_RRESP   : out std_logic_vector(1 downto 0);
    S_AXI_RVALID  : out std_logic;
    S_AXI_RREADY  : in  std_logic;
    -- RW/WO fields: register drives the DUT input port -- OUT on this entity
    enable                        : out std_logic;
    irq_mask                      : out std_logic_vector(3 downto 0);
    duty_cycle                    : out std_logic_vector(7 downto 0);
    prescaler                     : out std_logic_vector(15 downto 0);
    -- RO fields: DUT output port drives the register -- IN on this entity
    pwm_out                       : in  std_logic;
    period_done                   : in  std_logic;
    irq_status                    : in  std_logic_vector(3 downto 0);
